function SectionTitle({ title, href, activeTheme }) {
  return <div className="mb-4 flex items-end justify-between gap-4"><h2 className="text-[23px] font-semibold tracking-[-0.035em] text-slate-950 md:text-[26px]">{title}</h2>{href ? <a href={href} className={`whitespace-nowrap text-[13px] font-medium ${activeTheme.text} hover:opacity-80`}>View All →</a> : null}</div>;
}

function MegaMenu({ columns, activeTheme }) {
  return <div className="invisible absolute left-1/2 top-full z-50 w-[1040px] -translate-x-1/2 translate-y-4 rounded-2xl border border-slate-200 bg-white p-5 opacity-0 shadow-2xl shadow-slate-900/10 transition-all duration-200 group-hover:visible group-hover:translate-y-2 group-hover:opacity-100"><div className="grid grid-cols-3 gap-5">{columns.map((col) => <div key={col.title}><h3 className={`mb-3 text-[12px] font-medium uppercase tracking-[0.16em] ${activeTheme.text}`}>{col.title}</h3><div className="space-y-3">{col.items.map(([name, desc, img]) => <a key={name} href="#" className="flex gap-3 rounded-xl p-2 transition hover:bg-slate-50"><img src={img} alt={name} className="h-14 w-16 rounded-lg object-cover" /><span><b className="block text-[13px] font-medium text-slate-950">{name}</b><small className="text-[12px] font-normal text-slate-500">{desc}</small></span></a>)}</div></div>)}</div><div className={`mt-5 rounded-xl bg-gradient-to-r ${activeTheme.primary} p-4 text-white`}><b className="text-[15px] font-medium">Need a custom India tour?</b><span className="ml-3 text-[13px] font-normal text-white/85">Share date, budget and destination. Our expert will create a plan.</span><a href="#" className="float-right rounded-lg bg-white px-4 py-2 text-[12px] font-medium text-slate-700">Plan Now</a></div></div>;
}

